evaluators.evaluation_logic:
const checkpoints = [];
const ticketTypes = JSON.parse(localStorage.getItem('ticket_types') || '[]');
const ticketTiers = JSON.parse(localStorage.getItem('ticket_tiers') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const sessions = JSON.parse(localStorage.getItem('checkout_sessions') || '[]');

let hasCheapestPair = false;
let deliveryOkAndBudget = false;

const cart = carts.find(c => c.status === 'open');
if (cart) {
  const items = cartItems.filter(ci => ci.cart_id === cart.id);

  // Find cheapest available two-day adult tier
  const adultTypes = ticketTypes.filter(tt => tt.pass_type === 'two_day' && tt.ticket_category === 'adult');
  const adultTypeIds = adultTypes.map(tt => tt.id);
  const adultTiersAll = ticketTiers.filter(t => adultTypeIds.includes(t.ticket_type_id) && t.is_available !== false);
  let cheapestAdultTier = null;
  if (adultTiersAll.length) {
    cheapestAdultTier = adultTiersAll.reduce((min, t) => (t.price < min.price ? t : min), adultTiersAll[0]);
  }

  // Find cheapest available two-day child tier
  const childTypes = ticketTypes.filter(tt => tt.pass_type === 'two_day' && tt.ticket_category === 'child');
  const childTypeIds = childTypes.map(tt => tt.id);
  const childTiersAll = ticketTiers.filter(t => childTypeIds.includes(t.ticket_type_id) && t.is_available !== false);
  let cheapestChildTier = null;
  if (childTiersAll.length) {
    cheapestChildTier = childTiersAll.reduce((min, t) => (t.price < min.price ? t : min), childTiersAll[0]);
  }

  if (cheapestAdultTier && cheapestChildTier) {
    const adultItem = items.find(ci => ci.ticket_tier_id === cheapestAdultTier.id && ci.quantity >= 1);
    const childItem = items.find(ci => ci.ticket_tier_id === cheapestChildTier.id && ci.quantity >= 1);

    if (adultItem && childItem) {
      const adultType = adultTypes.find(tt => tt.id === cheapestAdultTier.ticket_type_id);
      const childType = childTypes.find(tt => tt.id === cheapestChildTier.ticket_type_id);
      const validA = adultType && Array.isArray(adultType.valid_days) ? adultType.valid_days.slice().sort().join(',') : '';
      const validC = childType && Array.isArray(childType.valid_days) ? childType.valid_days.slice().sort().join(',') : '';
      const sameDays = validA && validA === validC;
      hasCheapestPair = sameDays;

      if (hasCheapestPair) {
        const withinBudget = typeof cart.total === 'number' && cart.total <= 260;
        const session = sessions.find(s => s.cart_id === cart.id);
        const deliveryOk = session && (session.delivery_method === 'mobile_ticket' || session.delivery_method === 'e_ticket');
        deliveryOkAndBudget = withinBudget && deliveryOk;
      }
    }
  }
}

checkpoints.push({ passed: hasCheapestPair, weight: 0.6 });
checkpoints.push({ passed: deliveryOkAndBudget, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const scheduleItems = JSON.parse(localStorage.getItem('my_schedule_items') || '[]');
const performances = JSON.parse(localStorage.getItem('performances') || '[]');

function dateTimeToMinutes(dt) {
  if (!dt) return null;
  const d = new Date(dt);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
}

const minMinutes = 14 * 60;
const maxMinutes = 22 * 60;

const qualifying = scheduleItems
  .map(ms => performances.find(p => p.id === ms.performance_id))
  .filter(p => {
    if (!p) return false;
    if (p.day !== 'sunday') return false;
    if (!p.is_music_performance) return false;
    const m = dateTimeToMinutes(p.start_time);
    if (m == null) return false;
    return m >= minMinutes && m <= maxMinutes;
  });

const uniqueStageIds = Array.from(new Set(qualifying.map(p => p.stage_id))).filter(Boolean);

checkpoints.push({ passed: qualifying.length >= 1, weight: 0.3 });
checkpoints.push({ passed: qualifying.length >= 2, weight: 0.3 });
checkpoints.push({ passed: qualifying.length >= 3 && uniqueStageIds.length >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const tastingItems = JSON.parse(localStorage.getItem('tasting_list_items') || '[]');
const dishes = JSON.parse(localStorage.getItem('dishes') || '[]');

const qualifying = tastingItems
  .map(t => dishes.find(d => d.id === t.dish_id))
  .filter(d => {
    if (!d) return false;
    if (d.dish_type !== 'main') return false;
    const isVeg = d.is_vegetarian || (Array.isArray(d.dietary_tags) && d.dietary_tags.includes('vegetarian'));
    if (!isVeg) return false;
    if (typeof d.price !== 'number' || d.price > 15.0) return false;
    if (typeof d.average_rating !== 'number' || d.average_rating < 4.0) return false;
    return true;
  });

const cuisinesSet = new Set(qualifying.map(d => (d.cuisine || '').toLowerCase()).filter(Boolean));
const distinctCuisines = cuisinesSet.size;

checkpoints.push({ passed: qualifying.length >= 1, weight: 0.3 });
checkpoints.push({ passed: qualifying.length >= 2, weight: 0.3 });
checkpoints.push({ passed: qualifying.length >= 3 && distinctCuisines >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const regs = JSON.parse(localStorage.getItem('workshop_registrations') || '[]');

function dateTimeToMinutes(dt) {
  if (!dt) return null;
  const d = new Date(dt);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
}

const qualifyingActivities = activities.filter(a => {
  if (!a) return false;
  if (a.day !== 'saturday') return false;
  if (a.activity_type !== 'dance_workshop') return false;
  if (!a.is_free) return false;
  if (a.level !== 'intermediate') return false;
  const m = dateTimeToMinutes(a.start_time);
  if (m == null) return false;
  return m < 15 * 60;
});

const qualifyingActivityIds = new Set(qualifyingActivities.map(a => a.id));
const qualifyingRegs = regs.filter(r => qualifyingActivityIds.has(r.activity_id));

const withContactInfo = qualifyingRegs.filter(r => {
  const nameOk = typeof r.registrant_name === 'string' && r.registrant_name.trim().length > 0;
  const emailOk = typeof r.registrant_email === 'string' && r.registrant_email.trim().length > 0;
  return nameOk && emailOk;
});

checkpoints.push({ passed: qualifyingRegs.length >= 1, weight: 0.6 });
checkpoints.push({ passed: withContactInfo.length >= 1, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const artists = JSON.parse(localStorage.getItem('artists') || '[]');
const performances = JSON.parse(localStorage.getItem('performances') || '[]');
const lists = JSON.parse(localStorage.getItem('artist_lists') || '[]');
const listItems = JSON.parse(localStorage.getItem('artist_list_items') || '[]');

function dateTimeToMinutes(dt) {
  if (!dt) return null;
  const d = new Date(dt);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
}

const satNightArtistIdsSet = new Set(
  performances
    .filter(p => {
      if (!p) return false;
      if (p.day !== 'saturday') return false;
      if (!p.is_music_performance) return false;
      const m = dateTimeToMinutes(p.start_time);
      if (m == null) return false;
      return m >= 18 * 60;
    })
    .map(p => p.artist_id)
);

const satList = lists.find(l => l && l.name === 'Saturday Night');
let headlinerCount = 0;
let localCount = 0;

if (satList) {
  const ids = Array.from(
    new Set(
      listItems
        .filter(li => li.artist_list_id === satList.id)
        .map(li => li.artist_id)
    )
  );

  const qualifyingArtists = ids
    .map(id => artists.find(a => a.id === id))
    .filter(a => a && satNightArtistIdsSet.has(a.id));

  headlinerCount = qualifyingArtists.filter(a => a.artist_type === 'headliner').length;
  localCount = qualifyingArtists.filter(a => a.artist_type === 'local').length;
}

checkpoints.push({ passed: !!satList && headlinerCount >= 1 && localCount >= 1, weight: 0.3 });
checkpoints.push({ passed: !!satList && headlinerCount >= 2, weight: 0.3 });
checkpoints.push({ passed: !!satList && headlinerCount >= 2 && localCount >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const donations = JSON.parse(localStorage.getItem('donations') || '[]');
const funds = JSON.parse(localStorage.getItem('donation_funds') || '[]');
const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

const youthFundIds = funds
  .filter(f => {
    const text = ((f.name || '') + ' ' + (f.description || '')).toLowerCase();
    return text.includes('youth') && text.includes('music');
  })
  .map(f => f.id);

const qualifyingDonations = donations.filter(d => {
  if (!youthFundIds.includes(d.fund_id)) return false;
  if (typeof d.amount !== 'number' || d.amount < 20 || d.amount > 30) return false;
  if (d.payment_method !== 'credit_card') return false;
  if (!d.newsletter_opt_in) return false;
  return true;
});

const donationWithSubscription = qualifyingDonations.some(d => {
  const sub = subs.find(s => s.email === d.donor_email);
  return sub && sub.subscribed && sub.source === 'donation';
});

checkpoints.push({ passed: qualifyingDonations.length >= 1, weight: 0.5 });
checkpoints.push({ passed: donationWithSubscription, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const familyItems = JSON.parse(localStorage.getItem('family_plan_items') || '[]');
const activities = JSON.parse(localStorage.getItem('activities') || '[]');

function dateTimeToMinutes(dt) {
  if (!dt) return null;
  const d = new Date(dt);
  if (isNaN(d.getTime())) return null;
  return d.getHours() * 60 + d.getMinutes();
}

const minMinutes = 12 * 60;
const maxMinutes = 17 * 60;

const qualifying = familyItems
  .map(fp => activities.find(a => a.id === fp.activity_id))
  .filter(a => {
    if (!a) return false;
    if (a.day !== 'sunday') return false;
    if (!a.is_kids_focused) return false;
    if (!a.is_family_friendly) return false;
    if (typeof a.average_rating !== 'number' || a.average_rating < 4.5) return false;
    const m = dateTimeToMinutes(a.start_time);
    if (m == null) return false;
    return m >= minMinutes && m <= maxMinutes;
  });

checkpoints.push({ passed: qualifying.length >= 1, weight: 0.5 });
checkpoints.push({ passed: qualifying.length >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const saved = JSON.parse(localStorage.getItem('saved_map_locations') || '[]');
const mapLocations = JSON.parse(localStorage.getItem('map_locations') || '[]');
const vendors = JSON.parse(localStorage.getItem('vendors') || '[]');

const pinnedFood = saved
  .map(sml => {
    const loc = mapLocations.find(m => m.id === sml.map_location_id);
    if (!loc) return null;
    const vendor = vendors.find(v => v.location_id === loc.id);
    return { sml, loc, vendor };
  })
  .filter(x => {
    if (!x || !x.loc || !x.vendor) return false;
    if (x.loc.location_type !== 'food_vendor') return false;
    const walking = typeof x.loc.walking_time_from_main_stage === 'number' ? x.loc.walking_time_from_main_stage : null;
    if (walking == null || walking > 3) return false;
    return ['main', 'dessert', 'drink'].includes(x.vendor.vendor_food_type);
  });

const hasMain = pinnedFood.some(x => x.vendor.vendor_food_type === 'main');
const hasDessert = pinnedFood.some(x => x.vendor.vendor_food_type === 'dessert');
const hasDrink = pinnedFood.some(x => x.vendor.vendor_food_type === 'drink');
const hasAllThreeTypes = hasMain && hasDessert && hasDrink;

let orderOk = false;
if (hasAllThreeTypes) {
  const typeMinOrder = { main: Infinity, dessert: Infinity, drink: Infinity };
  pinnedFood.forEach(x => {
    const t = x.vendor.vendor_food_type;
    if (typeof x.sml.route_order === 'number' && x.sml.route_order < typeMinOrder[t]) {
      typeMinOrder[t] = x.sml.route_order;
    }
  });
  orderOk =
    typeMinOrder.main < typeMinOrder.dessert &&
    typeMinOrder.dessert < typeMinOrder.drink &&
    typeMinOrder.main < Infinity &&
    typeMinOrder.dessert < Infinity &&
    typeMinOrder.drink < Infinity;
}

checkpoints.push({ passed: hasAllThreeTypes, weight: 0.5 });
checkpoints.push({ passed: hasAllThreeTypes && orderOk, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
